Object.assign(window.I18N_AUTO.uz, {'28 букв арабского языка':'Arabcha 28 ta harf','49 тем с тестами':'Testlar bilan 49 ta mavzu','28 букв арабского языка. Нажми на букву, чтобы узнать подробности.':'Arabcha 28 harf. Batafsil ma\'lumot olish uchun xat ustiga bosing.','49 тем в 6 группах — по уровню сложности, цепочкой от строения имени до сложного синтаксиса. После каждой темы — тест, после каждых 4 тем — большой контрольный.':'6 ta guruhda 49 ta mavzu - qiyinchilik darajasiga ko\'ra, nom tuzilishidan murakkab sintaksisgacha zanjirda. Har bir mavzudan keyin test, har 4 ta mavzudan keyin katta test.','Большой тест: Арабский → Определённый':'Katta sinov: arabcha → aniq','Большой тест: Солнечные → Виды':'Katta sinov: Quyosh → Turlar','Большой тест: Личные → Относительные':'Katta sinov: Shaxsiy → Nisbiy','Большой тест: Три → Прилагательные':'Katta test: Uch → Sifatlar','Большой тест: Числительные → Порядковые':'Katta test: Raqamlar → Tartib','Большой тест: Именное → Глагольное':'Katta test: nominal → og\'zaki','Большой тест: Предлоги → Глагол:':'Katta test: Predloglar → Fe\'l:','Большой тест: Настоящее → Будущее':'Katta sinov: hozirgi → kelajak','Большой тест: Породы → Масдар':'Katta sinov: Zotlar → Masdar','Большой тест: Действительное → Отрицание':'Katta sinov: Haqiqiy → Salbiy','Большой тест: Обстоятельства: → Степени':'Katta sinov: Vaziyatlar: → Darajalar','Большой тест: Союзы → Дни,':'Katta sinov: Birlashmalar → Kunlar,','Очки навыка':'Malaka ballari','Таблица':'Jadval','Знакомство':'Tanishuv','Введите слово: رجل или мужчина…':'So\'zni kiriting: rjl yoki man...','день':'kun','Схема: где образуется звук':'Diagramma: tovush hosil bo\'ladigan joy','6 букв не соединяются с последующей буквой:':'6 ta harf keyingi harfga bog\'lanmagan:','6 букв (ا د ذ ر ز و) не соединяются слева — запомни их отдельно.':'6 ta harf (ạ d d dẖ r z w) chap tomonda bog\'lanmagan - ularni alohida eslab qoling.','↻ Сброс':'↻ Qayta tiklash','3 букв (обычно)':'3 ta harf (odatda)'});
Object.assign(window.I18N_AUTO.en, {'28 букв арабского языка':'28 letters of Arabic','49 тем с тестами':'49 topics with tests','28 букв арабского языка. Нажми на букву, чтобы узнать подробности.':'28 letters of Arabic. Click on a letter to find out more details.','49 тем в 6 группах — по уровню сложности, цепочкой от строения имени до сложного синтаксиса. После каждой темы — тест, после каждых 4 тем — большой контрольный.':'49 topics in 6 groups - according to difficulty level, in a chain from the structure of the name to complex syntax. After each topic there is a test, after every 4 topics there is a large test.','Большой тест: Арабский → Определённый':'Big test: Arabic → Certain','Большой тест: Солнечные → Виды':'Big test: Solar → Species','Большой тест: Личные → Относительные':'Big test: Personal → Relative','Большой тест: Три → Прилагательные':'Big test: Three → Adjectives','Большой тест: Числительные → Порядковые':'Big test: Numerals → Ordinal','Большой тест: Именное → Глагольное':'Big test: Nominal → Verbal','Большой тест: Предлоги → Глагол:':'Big test: Prepositions → Verb:','Большой тест: Настоящее → Будущее':'Big test: Present → Future','Большой тест: Породы → Масдар':'Big test: Breeds → Masdar','Большой тест: Действительное → Отрицание':'Big test: Real → Negative','Большой тест: Обстоятельства: → Степени':'Big test: Circumstances: → Degrees','Большой тест: Союзы → Дни,':'Big test: Unions → Days,','Очки навыка':'Skill Points','Таблица':'Table','Знакомство':'Acquaintance','Введите слово: رجل или мужчина…':'Enter the word: رجل or man...','день':'day','Схема: где образуется звук':'Diagram: where sound is produced','6 букв не соединяются с последующей буквой:':'6 letters are not connected to the next letter:','6 букв (ا د ذ ر ز و) не соединяются слева — запомни их отдельно.':'6 letters (ا د ذ ر ز و) are not connected on the left - remember them separately.','↻ Сброс':'↻ Reset','3 букв (обычно)':'3 letters (usually)'});
Object.assign(window.I18N_AUTO.uz, {'Запомнил 10 слов':'10 ta so\'zni yodlab oldi','Запомнил 50 слов':'50 ta so\'zni yodlab oldi','50 карточек в повторении':'Har bir takrorlash uchun 50 ta karta','Слово с интервалом 14+ дней':'14+ kunlik interval bilan so\'z','= “-у” (rafʿ),':'= “-u” (rafʿ),','— studies (مرفوع, ending “-у”)':'- tadqiqotlar (mrfwʿ, “-u” bilan tugaydi)'});
Object.assign(window.I18N_AUTO.en, {'Запомнил 10 слов':'Memorized 10 words','Запомнил 50 слов':'Memorized 50 words','50 карточек в повторении':'50 cards per repetition','Слово с интервалом 14+ дней':'Word with an interval of 14+ days','= “-у” (rafʿ),':'= “-у” (rafʿ),','— studies (مرفوع, ending “-у”)':'- studies (مرفوع, ending “-у”)'});
Object.assign(window.I18N_AUTO.uz, {'🌱 Новичок I':'🌱 Yangi boshlovchi I','Вы вошли как':'sifatida tizimga kirgansiz','✅ Прогресс этого аккаунта сохраняется отдельно на этом устройстве. Зарегистрировано аккаунтов: 1.':'✅ Ushbu hisobning borishi ushbu qurilmada alohida saqlanadi. Ro\'yxatdan o\'tgan hisoblar: 1.','➕ Добавить слово или тему':'➕ So\'z yoki mavzu qo\'shing','Введи арабское слово, перевод и (по желанию) транскрипцию. Оно появится в мастерской с твоим именем.':'Arabcha so\'z, tarjima va (ixtiyoriy) transkripsiyani kiriting. U sizning ismingiz bilan ustaxonada paydo bo\'ladi.','Добавить':'Qo\'shish','Пока пусто. Добавь первое слово выше! ⬆️':'Hozircha bo\'sh. Yuqoridagi birinchi so\'zni qo\'shing! ⬆️','Тема (необязательно, напр. «Мои слова»)':'Mavzu (ixtiyoriy, masalan, "Mening so\'zlarim")','арабское слово · مثال':'Arabcha so\'z · mtẖạl','перевод на русский':'rus tiliga tarjima','транскрипция (по желанию)':'transkripsiya (ixtiyoriy)','🛡 Панель администратора. Видны все зарегистрированные ученики: логин, пароль, ранг и навык. Можно дать штраф (−100 XP), бонус (+100), назначить/снять администратора или удалить ученика.':'🛡Administrator paneli. Barcha ro\'yxatdan o\'tgan talabalar ko\'rinadi: login, parol, daraja va mahorat. Siz jarima (−100 XP), bonus (+100) berishingiz, administratorni tayinlashingiz/olib tashlashingiz yoki talabani olib tashlashingiz mumkin.','Логин':'Kirish','Пароль':'Parol','Ранг':'Daraja','🛡 система · рег. 06.06.2026':'🛡 tizim · reg. 06.06.2026','Всего зарегистрировано:':'Jami roʻyxatga olinganlar:','Штраф −100 XP':'-100 XP jarima','Бонус +100 XP':'Bonus +100 XP','Сделать/снять админа':'Administratorni yaratish/oʻchirish','Удалить ученика':'Talabani olib tashlash','Ур. 1':'Lv. 1','🔊 Прослушать':'🔊 Eshiting','👆 Нажми на любое слово — появится перевод и озвучка.':'👆 Istalgan so\'z ustiga bosing va tarjima va ovozli yozuv paydo bo\'ladi.','Это моя семья. Мой отец — врач. Моя мать — учительница. У меня есть брат и сестра. Мы живём в большом доме.':'Bu mening oilam. Mening otam shifokor. Onam o\'qituvchi. Mening akam va singlim bor. Biz katta uyda yashaymiz.','🙈 Скрыть перевод':'🙈 Tarjimani yashirish','▶️ Прослушать диалог':'▶️ Dialogni tinglang','👂 Слушай и переводи сам! Нажми на реплику, чтобы увидеть её перевод — или открой весь перевод кнопкой внизу.':'👂 Tinglang va o\'zingiz tarjima qiling! Tarjimani ko‘rish uchun replika ustiga bosing yoki quyidagi tugma yordamida butun tarjimani oching.','Мир вам (здравствуйте)':'Sizga tinchlik bo\'lsin (salom)','И вам мир':'Sizga ham tinchlik','Доброе утро':'Xayrli tong','Доброе утро (ответ)':'Xayrli tong (javob)','Как дела?':'yaxshimisiz?','Хорошо, слава Богу. А ты?':'Yaxshi, Xudoga shukur. Sizchi?','Хорошо, спасибо':'OK, rahmat','Меня зовут Умар. А тебя?':'Mening ismim Umar. Sizchi?','Меня зовут Ахмад':'Mening ismim Ahmad','Приятно познакомиться, Ахмад':'Siz bilan tanishganimdan xursandman, Ahmad','Мне тоже приятно':'Men ham mamnunman','Я из Египта. А ты?':'Men Misrdanman. Sizchi?','Я из России':'Men Rossiyadanman','Ты говоришь по-арабски?':'Arabcha gapirasizmi?','Да, немного':'Ha, bir oz','Прекрасно! Твой язык хороший':'Ajoyib! Tilingiz yaxshi','Спасибо, я сейчас учусь':'Rahmat, men hozir o\'qiyman','Сколько тебе лет?':'Yoshingiz nechada?','Мне двадцать лет':'Men yigirma yoshdaman','Чем занимаешься?':'Nima qilyapsan?','Я студент в университете':'Men universitet talabasiman','Замечательно. Ты завтра занят?':'Ajoyib. Ertaga bandmisiz?','Нет, я свободен':'Yo‘q, men bo‘shman','Отлично! Встретимся в кафе':'Ajoyib! Men bilan kafeda uchrashing','Хорошая идея. До встречи':'Yaxshi fikr. Keyinroq ko‘rishguncha','До свидания':'Xayr','Сначала смотри только на арабскую сторону и пытайся вспомнить перевод сам.':'Avvaliga faqat arab tomoniga qarang va tarjimani o\'zingiz eslab qolishga harakat qiling.','Нажми на карточку, чтобы перевернуть её и увидеть перевод и транслитерацию.':'Kartani ag\'darish va tarjima va transliteratsiyani ko\'rish uchun ustiga bosing.','Кнопка 🔊 произносит слово вслух выбранным голосом (мужским или женским).':'🔊 tugmasi tanlangan ovozda (erkak yoki ayol) so\'zni baland ovozda talaffuz qiladi.','Вспомнил слово — жми «✓ Знаю», не вспомнил — «❌ Не знаю».':'Agar so\'zni eslab qolsangiz, "✓ Men bilaman" tugmasini bosing; eslamasangiz, “❌ Bilmayman” tugmasini bosing.','В колоде 15 слов. Слова, отмеченные «Знаю», попадают в твой прогресс.':'To\'plamda 15 ta so\'z bor. "Bilaman" deb belgilangan so\'zlar muvaffaqiyatingizga kiradi.','Проговаривай транслитерацию вслух — так слово запоминается быстрее.':'Transliteratsiyani baland ovozda ayting - bu so\'zni tezroq eslab qolishingiz mumkin.','На экране — арабское слово и его транслитерация.':'Ekranda arabcha so\'z va uning transliteratsiyasi.','Выбери правильный перевод из 4 вариантов.':'4 ta variantdan toʻgʻri tarjimani tanlang.','Правильный ответ подсветится зелёным, неверный — красным.':'To\'g\'ri javob yashil rang bilan, noto\'g\'ri javob qizil rang bilan belgilanadi.','Всего 10 вопросов, за каждый верный — очко.':'Faqat 10 ta savol bor, har bir to\'g\'ri savol uchun siz bir ball olasiz.','Будь внимателен — иногда перевод подменяют похожим по теме словом.':'Ehtiyot bo\'ling - ba\'zida tarjima mavzuga o\'xshash so\'z bilan almashtiriladi.','Показывается пара: арабское слово = перевод.':'Juftlik ko\'rsatilgan: arabcha so\'z = tarjima.','Реши, верное ли это соответствие.':'Ushbu moslik to\'g\'ri yoki yo\'qligini aniqlang.','Нажми «Верно» или «Неверно».':'"To\'g\'ri" yoki "Yolg\'on" ni bosing.','10 раундов, очко за каждый правильный ответ.':'10 tur, har bir to\'g\'ri javob uchun ball.','Опирайся на транслитерацию, чтобы понять порядок звуков в слове.':'So\'zdagi tovushlar tartibini tushunish uchun transliteratsiyaga tayan.','Вверху — перевод, транслитерация и эмодзи слова.':'Yuqori qismida so\'zning tarjimasi, transliteratsiyasi va emoji mavjud.','Из перемешанных букв внизу собери арабское слово в поле ввода.':'Quyidagi aralashgan harflardan arabcha so‘zni kiritish maydoniga yig‘ing.','Кнопка «↻ Очистить» сбрасывает набранное.':'“↻ Clear” tugmasi kiritilgan maʼlumotlarni qayta tiklaydi.','Нажми «Проверить». Помни: арабский пишется справа налево.':'"Tekshirish" tugmasini bosing. Esingizda bo\'lsin: arabcha o\'ngdan chapga yoziladi.','Запоминай, где лежат карточки, которые ты уже открывал.':'Siz allaqachon ochgan kartalar qaerda joylashganligini eslang.','Перед тобой закрытые карточки: половина — арабские слова, половина — переводы.':'Sizning oldingizda pastga qaragan kartalar: yarmi arabcha so\'zlar, yarmi tarjimalar.','Открывай по две карточки за ход.':'Har bir turda ikkita kartani ko\'rsating.','Если арабское слово и его перевод совпали — пара остаётся открытой.':'Agar arabcha so\'z va uning tarjimasi mos kelsa, juftlik ochiq qoladi.','Найди все пары за наименьшее число ходов.':'Eng kam harakatlardagi barcha juftlarni toping.','Арабское слово собирается справа налево — первая буква стоит справа.':'Arabcha so\'z o\'ngdan chapga yig\'ilgan - birinchi harf o\'ng tomonda.','Даны перевод и транслитерация слова.':'So\'zning tarjimasi va transliteratsiyasi berilgan.','Буквы перемешаны — нажимай на них в правильном порядке.':'Harflar aralashtiriladi - ularni to\'g\'ri tartibda bosing.','Кнопка «↻ Начать сначала» возвращает все буквы.':'“↻ Boshdan boshlash” tugmasi barcha harflarni qaytaradi.','Нажми «Проверить», когда соберёшь слово.':'So\'zni tugatgandan so\'ng "Tekshirish" tugmasini bosing.','Сначала прочитай перевод всего предложения — он подскажет ответ.':'Birinchidan, butun jumlaning tarjimasini o\'qing - bu sizga javobni aytib beradi.','Показано предложение с пропущенным словом и его перевод.':'Yo\'qolgan so\'zli gap va uning tarjimasi ko\'rsatiladi.','Выбери из вариантов слово, которое подходит в пропуск.':'Variantlardan bo\'sh joyga mos keladigan so\'zni tanlang.','Правильный ответ встанет на место пропуска.':'To\'g\'ri javob bo\'sh joyda paydo bo\'ladi.','Пройди все предложения по очереди.':'Barcha jumlalarni navbatma-navbat ko\'rib chiqing.','Начинай с частых букв: ا، ل، م، ن، ر.':'Tez-tez harflar bilan boshlang: ạ, l, m, n, r.','Загадано арабское слово, видны только пустые клетки.':'Arabcha so\'z yashirin, faqat bo\'sh katakchalar ko\'rinadi.','Нажимай на буквы арабской клавиатуры на экране.':'Ekrandagi arab klaviaturasining harflarini bosing.','Есть буква в слове — открывается; нет — добавляется ошибка.':'So\'zda harf bor - u ochiladi; yo\'q - xato qo\'shildi.','Допускается до 6 ошибок. Угадай слово раньше!':'6 tagacha xatolikka ruxsat beriladi. Avval so\'zni toping!','Сначала ищи короткие слова — их легче заметить.':'Avval qisqa so\'zlarni qidiring - ularni aniqlash osonroq.','В сетке букв спрятаны слова из списка справа.':'Harflar panjarasida o\'ngdagi ro\'yxatdagi so\'zlar yashiringan.','Слова идут по горизонтали или по вертикали.':'So\'zlar gorizontal yoki vertikal ravishda boradi.','Кликни на первую, затем на последнюю букву слова.':'So\'zning birinchi, so\'ng oxirgi harfini bosing.','Найди все слова из списка.':'Roʻyxatdagi barcha soʻzlarni toping.','На телефоне удерживай слово пальцем и тяни к переводу.':'Telefoningizda soʻzni barmogʻingiz bilan ushlab turing va tarjima qilish uchun uni torting.','Слева — арабские слова, справа — переводы.':'Chapda arabcha so\'zlar, o\'ngda tarjimalar.','Перетащи арабское слово на его перевод.':'Arabcha so‘zni tarjimasiga torting.','Верная пара соединится и подсветится зелёным.':'To\'g\'ri juftlik ulanadi va yashil rangda yonadi.','Соедини все пары.':'Barcha juftlarni ulang.','Не уверен в категории — вспомни перевод слова.':'Kategoriya haqida ishonchim komil emas - so\'zning tarjimasini eslang.','Даны слова из трёх разных категорий вперемешку.':'Uch xil toifadagi so\'zlar aralashtirib berilgan.','Перетащи каждое слово в нужную корзину-категорию.':'Har bir so\'zni kerakli turkum savatiga torting.','Верное попадание — зелёное, ошибка — красная.':'To\'g\'ri urish yashil rangda, xato qizil rangda.','Распредели все слова.':'Barcha so\'zlarni taqsimlang.','Пиши коротко — главное слово, без артиклей и лишних букв.':'Qisqacha yozing - asosiy so\'z, maqolalar va qo\'shimcha harflarsiz.','Включается таймер на 60 секунд.':'Taymer 60 soniya davomida boshlanadi.','На экране арабское слово — впиши его перевод на русском и нажми Enter.':'Ekranda arabcha so\'z bor - uning rus tilidagi tarjimasini kiriting va Enter tugmasini bosing.','За каждый правильный перевод — очко.':'Har bir to\'g\'ri tarjima uchun - ball.','Успей перевести как можно больше слов!':'Iloji boricha ko\'proq so\'zlarni tarjima qilishga shoshiling!','В арабском часто сначала идёт глагол, потом подлежащее.':'Arab tilida ko\'pincha birinchi navbatda fe\'l, keyin esa mavzu keladi.','Дан перевод предложения.':'Gapning tarjimasi berilgan.','Из перемешанных слов собери предложение в правильном порядке.':'Chalkashib ketgan so‘zlardan gapni to‘g‘ri tartibda yig‘ing.','Нажимай слова по очереди; «↻ Сброс» очищает.':'So\'zlarni birma-bir bosing; "↻ Qayta tiklash" o\'chiriladi.','Проверь — порядок слов должен совпасть.':'So\'z tartibi mos kelishini tekshiring.','Поле ввода само переходит к следующей пропущенной букве.':'Kirish maydoni avtomatik ravishda keyingi etishmayotgan harfga o\'tadi.','В слове скрыто несколько букв — это пустые поля.':'So\'zda bir nechta harflar yashiringan - bu bo\'sh maydonlar.','Впиши недостающие арабские буквы.':'Yo\'qolgan arab harflarini to\'ldiring.','Помогают эмодзи, перевод и транслитерация.':'Emoji, tarjima va transliteratsiya yordam beradi.','Нажми «Проверить».':'"Tekshirish" tugmasini bosing.','Не зависай над ошибкой — здесь важен непрерывный поток.':'Xato ustiga kursorni olib kelmang - bu erda doimiy oqim muhim ahamiyatga ega.','Гонка на 60 секунд.':'60 soniya davomida poyga qiling.','Показывается арабское слово и 4 варианта перевода.':'Arabcha so\'z va 4 ta tarjima varianti ko\'rsatilgan.','Выбирай правильный как можно быстрее — сразу идёт следующий.':'To\'g\'risini iloji boricha tezroq tanlang - keyingisi darhol keladi.','Набери максимум переводов до конца времени.':'Vaqt tugashidan oldin maksimal o\'tkazmalarni to\'plang.','Связывай образ напрямую с арабским словом, минуя русский.':'Rasmni rus tilini chetlab o\'tib, arabcha so\'z bilan to\'g\'ridan-to\'g\'ri bog\'lang.','Показан эмодзи-картинка.':'Emoji rasmi ko\'rsatiladi.','Выбери арабское слово, которое ей соответствует.':'Unga mos keladigan arabcha so\'zni tanlang.','Верный ответ — зелёный, неверный — красный (правильный подсветится).':'To\'g\'ri javob yashil rangda, noto\'g\'ri javob qizil rangda (to\'g\'ri javob ajratib ko\'rsatiladi).','Пройди 10 картинок.':'10 ta rasmni ko\'rib chiqing.','Переключи мужской/женский голос слева, чтобы привыкнуть к разному произношению.':'Turli talaffuzlarga o‘rganish uchun chap tarafdagi erkak/ayol ovozini almashtiring.','Нажми 🔊, чтобы услышать арабское слово.':'Arabcha soʻzni eshitish uchun 🔊 tugmasini bosing.','Выбери из вариантов то слово, которое прозвучало.':'Variantlar orasidan eshitilgan so\'zni tanlang.','Слушать можно несколько раз.':'Siz bir necha marta tinglashingiz mumkin.','Пройди 10 слов на слух.':'Tinglash orqali 10 ta so\'zdan o\'ting.','Начни со слова, перевод которого знаешь точно.':'Tarjimasini aniq biladigan so\'z bilan boshlang.','Мини-кроссворд: одно слово по горизонтали и одно по вертикали, они пересекаются буквой.':'Mini krossvord: bir so\'z gorizontal va bitta so\'z vertikal, ular harf bilan kesishadi.','Читай подсказки-переводы.':'Tarjima bo\'yicha maslahatlarni o\'qing.','Впиши арабские буквы в клетки.':'Qutilarga arabcha harflarni yozing.','Заполни весь кроссворд.':'To\'liq krossvordni to\'ldiring.','Думай темами: животное — к животному, еда — к еде.':'Mavzular bo\'yicha o\'ylab ko\'ring: hayvondan hayvonga, ovqatdan ovqatga.','Показано слово и его тема (категория).':'So\'z va uning mavzusi (toifasi) ko\'rsatiladi.','Выбери из вариантов слово ИЗ ТОЙ ЖЕ категории.':'Variantlardan BU toifadagi so\'zni tanlang.','Верно — очко и следующий раунд.':'To\'g\'ri - ochko va keyingi bosqich.','Всего 8 раундов.':'Jami 8 tur.','Договоритесь: Игрок 1 — слева, Игрок 2 — справа, и держите пальцы на своих клавишах.':'Qabul qiling: 1-o\'yinchi chapda, 2-o\'yinchi o\'ngda va barmoqlaringizni tugmachalaringizda ushlab turing.','Игра для двоих на одном экране/клавиатуре.':'Bir ekranda/klaviaturada ikkita o\'yin.','Обоим показывается одно арабское слово и 4 варианта перевода.':'Ikkalasida ham bitta arabcha so\'z va 4 ta tarjima varianti ko\'rsatilgan.','Игрок 1 отвечает клавишами 1·2·3·4, Игрок 2 — клавишами 7·8·9·0 (или мышкой).':'1-o‘yinchi 1·2·3·4 tugmalari bilan, 2-o‘yinchi 7·8·9·0 tugmalari bilan (yoki sichqoncha bilan) javob beradi.','Кто первым ответит верно — получает очко. 10 раундов, побеждает набравший больше.':'Kim birinchi bo\'lib to\'g\'ri javob bersa, ochko oladi. 10 raund, eng ko\'p g\'alaba qozongan.','Повторный клик по выбранному слову снимает выделение.':'Tanlangan so\'zni yana bosish tanlovni olib tashlaydi.','Два столбика: слева арабские слова, справа переводы.':'Ikki ustun: arabcha so\'zlar chapda, tarjimalar o\'ngda.','Кликни слово в одном столбике, затем его пару в другом.':'Bir ustundagi so\'zni, keyin boshqasida uning juftligini bosing.','Верная пара подсветится и зафиксируется.':'To\'g\'ri juftlik ajratib ko\'rsatiladi va yozib olinadi.','Сопоставь все слова.':'Barcha so\'zlarni moslang.','Это игра на скорость самопроверки — не задерживайся на карточке.':'Bu o\'z-o\'zini sinab ko\'rish tezligi o\'yini - kartada qolib ketmang.','Карточки листаются быстро, слово сразу произносится вслух.':'Kartochkalar tezda aylantiriladi, so\'z darhol baland ovozda talaffuz qilinadi.','Знаешь слово — жми «✓ Знаю», не знаешь — «📖 Учить».':'Agar so\'zni bilsangiz, "✓ Men bilaman" tugmasini bosing; agar bilmasangiz, "📖 O\'rganish" tugmasini bosing.','«Знаю» добавляет слово в изученные.':'"Bilaman" so\'zini o\'rganganlarga qo\'shadi.','Пройди всю колоду в своём темпе.':'O\'zingizning tezligingiz bilan butun kemadan o\'ting.','Сначала повтори слово вслух, потом пиши — так лучше слышишь буквы.':'Birinchidan, so\'zni baland ovozda takrorlang, keyin yozing - bu bilan siz harflarni yaxshiroq eshitishingiz mumkin.','Нажми 🔊 и послушай слово (можно «🐢 Медленно»).':'🔊 tugmasini bosing va so\'zni tinglang (siz “🐢 Sekin” qilishingiz mumkin).','Впечатай слово арабскими буквами в поле (справа налево).':'So\'zni arabcha harflar bilan maydonga kiriting (o\'ngdan chapga).','Огласовки можно не ставить — проверяется без них.':'Unli tovushlarni qo\'yishingiz shart emas - ularsiz tekshiriladi.','Нажми «Проверить». Всего 10 слов.':'"Tekshirish" tugmasini bosing. Faqat 10 so\'z.','📋 Как играть — правила':'📋 Qanday o\'ynash kerak - qoidalar','▶️ Начать игру':'▶️ O\'yinni boshlang','Кликни по карточке, чтобы перевернуть':'Kartani ag\'darish uchun ustiga bosing','Карта':'Xarita','из 15':'15 dan','❌ Не знаю':'❌ Bilmayman','🔊 Произнести':'🔊 Ayting','✓ Знаю':'✓ Men bilaman','Что означает это слово?':'Bu so\'z nimani anglatadi?','✓ Верно':'✓ To\'g\'ri','✗ Неверно':'✗ Noto\'g\'ri','↻ Очистить':'↻ Aniq','Проверить':'Tekshirish','Найдено:':'Topildi:','Ходы:':'Harakatlar:','Собери слово:':'So\'zni to\'plang:','↻ Начать сначала':'↻ Qaytadan boshlang','Выбери пропущенное слово:':'Yo\'qolgan so\'zni tanlang:','Жизней: 6 / 6':'Yashaydi: 6/6','я не хочу (lā urīd) 🙅':'Men xohlamayman (lā urīd) 🙅','Клик на первую и последнюю букву слова':'So\'zning birinchi va oxirgi harfini bosing','Найди слова (5):':'So\'zlarni toping (5):','Перетащи арабские слова к их переводам':'Arabcha soʻzlarni tarjimalariga torting','Арабские слова':'Arabcha so\'zlar','Переводы':'Tarjimalar','Распредели слова по категориям':'So\'zlarni turkumlash','Печатай перевод и нажимай Enter':'Tarjimani kiriting va Enter tugmasini bosing','Перевод на русском...':'Rus tiliga tarjima...','Собери предложение: «Я студент.»':'Bir jumla tuzing: "Men talabaman".','Переведено:':'Tarjima qilingan:','Что это?':'Bu nima?','Послушай и выбери правильное слово':'Tinglang va to\'g\'ri so\'zni tanlang','По горизонтали:':'Gorizontal:','1. гранат':'1. anor','По вертикали:':'Vertikal:','2. берег':'2. qirg‘oq','Проверить кроссворд':'Krossvordni tekshiring','💡 Подсказка':'💡 Maslahat','Найди слово той же категории:':'Xuddi shu toifadagi so\'zni toping:','(такси)':'(taksi)','🏅 Получено достижение: Геймер!':'🏅 Olingan yutuq: geymer!','🔵 Игрок 1':'🔵 1-o‘yinchi','1. поднял':'1. ko‘tarilgan','2. сура':'2. sura','3. география':'3. geografiya','4. разговор / беседа':'4. suhbat / suhbat','Клавиши: 1 2 3 4':'Tugmalar: 1 2 3 4','🔴 Игрок 2':'🔴 2-o‘yinchi','Клавиши: 7 8 9 0':'Tugmalar: 7 8 9 0','Сопоставь арабские слова с переводами. Клик по одному, затем по другому.':'Arabcha so‘zlarni tarjimalar bilan moslang. Birini, keyin ikkinchisini bosing.','из 2833':'2833 dan','📖 Учить':'📖 O\'rgating','Послушай слово и запиши его арабскими буквами:':'So\'zni tinglang va arab harflari bilan yozing:','🔊 Воспроизвести':'🔊 O\'ynang','подсказка: ширина':'maslahat: kenglik','Слово 1 из 10':'10dan 1-so\'z'});
